var src = inputs.Length > 0 ? inputs[0] : null;
    if (src == null)
        return new PixelBuffer(context.TileSize, context.TileSize);

    var style = GetChoice(parameters, "style", "cartoon");
    var strength = GetFloat(parameters, "strength", 0.5f);
    var detail = GetFloat(parameters, "detail", 0.5f);
    var smoothness = GetFloat(parameters, "smoothness", 0.3f);
    var preserveAlpha = GetBool(parameters, "preserveAlpha", true);

    var size = context.TileSize;
    var result = new PixelBuffer(size, size);

    switch (style)
    {
        case "oilPaint":
            OilPaint(src, result, strength, size);
            break;
        case "emboss":
            Emboss(src, result, strength, size);
            break;
        case "pixelOutline":
            PixelOutline(src, result, strength, size);
            break;
        case "posterize":
            Posterize(src, result, strength, detail, size);
            break;
        case "watercolor":
            Watercolor(src, result, strength, smoothness, size);
            break;
        default: // cartoon
            Cartoon(src, result, strength, smoothness, size);
            break;
    }

    // Handle alpha
    if (!preserveAlpha)
    {
        result.ParallelForEachPixel((x, y) =>
        {
            var (r, g, b, _) = result.GetPixel(x, y);
            result.SetPixel(x, y, r, g, b, 1f);
        });
    }

    return result;

private static void Cartoon(PixelBuffer src, PixelBuffer dst, float strength, float smoothness, int size)
{
    // Quantize colors + edge detection
    dst.ParallelForEachPixel((x, y) =>
    {
        var (r, g, b, a) = src.GetPixel(x, y);

        // Color quantization
        var levels = Math.Max(2, (int)(4 + strength * 8));
        var step = 1f / levels;
        r = MathF.Round(r / step) * step;
        g = MathF.Round(g / step) * step;
        b = MathF.Round(b / step) * step;

        // Simple edge detection (Sobel)
        float gxR = 0, gyR = 0;
        for (var dy = -1; dy <= 1; dy++)
        {
            for (var dx = -1; dx <= 1; dx++)
            {
                var (pr, pg, pb, _) = src.GetPixelWrapped(x + dx, y + dy);
                var lum = 0.299f * pr + 0.587f * pg + 0.114f * pb;
                var sx = (dx == 0 ? 0f : dx > 0 ? 1f : -1f) * (dy == 0 ? 2f : 1f);
                var sy = (dy == 0 ? 0f : dy > 0 ? 1f : -1f) * (dx == 0 ? 2f : 1f);
                gxR += lum * sx;
                gyR += lum * sy;
            }
        }
        var edge = MathF.Sqrt(gxR * gxR + gyR * gyR);
        var edgeFactor = Math.Clamp(edge * strength * 2f, 0f, 1f);
        var ink = 1f - edgeFactor;

        dst.SetPixel(x, y,
            Math.Clamp(r * ink, 0f, 1f),
            Math.Clamp(g * ink, 0f, 1f),
            Math.Clamp(b * ink, 0f, 1f), a);
    });
}

private static void OilPaint(PixelBuffer src, PixelBuffer dst, float strength, int size)
{
    var radius = Math.Max(2, (int)(strength * 6) + 1);
    var levels = 8;

    dst.ParallelForEachPixel((x, y) =>
    {
        var histR = new int[levels];
        var histG = new int[levels];
        var histB = new int[levels];
        var total = 0;

        for (var dy = -radius; dy <= radius; dy++)
        {
            for (var dx = -radius; dx <= radius; dx++)
            {
                var (pr, pg, pb, _) = src.GetPixelWrapped(x + dx, y + dy);
                var binR = (int)Math.Clamp(pr * levels, 0, levels - 1);
                var binG = (int)Math.Clamp(pg * levels, 0, levels - 1);
                var binB = (int)Math.Clamp(pb * levels, 0, levels - 1);
                histR[binR]++;
                histG[binG]++;
                histB[binB]++;
                total++;
            }
        }

        // Find dominant bins
        var maxR = 0; var maxG = 0; var maxB = 0;
        var idxR = 0; var idxG = 0; var idxB = 0;
        for (var i = 0; i < levels; i++)
        {
            if (histR[i] > maxR) { maxR = histR[i]; idxR = i; }
            if (histG[i] > maxG) { maxG = histG[i]; idxG = i; }
            if (histB[i] > maxB) { maxB = histB[i]; idxB = i; }
        }

        // Average pixels in dominant bins
        var sumR = 0f; var sumG = 0f; var sumB = 0f;
        var cntR = 0; var cntG = 0; var cntB = 0;
        for (var dy = -radius; dy <= radius; dy++)
        {
            for (var dx = -radius; dx <= radius; dx++)
            {
                var (pr, pg, pb, _) = src.GetPixelWrapped(x + dx, y + dy);
                if ((int)(pr * levels) == idxR) { sumR += pr; cntR++; }
                if ((int)(pg * levels) == idxG) { sumG += pg; cntG++; }
                if ((int)(pb * levels) == idxB) { sumB += pb; cntB++; }
            }
        }

        dst.SetPixel(x, y,
            cntR > 0 ? sumR / cntR : 0f,
            cntG > 0 ? sumG / cntG : 0f,
            cntB > 0 ? sumB / cntB : 0f, 1f);
    });
}

private static void Emboss(PixelBuffer src, PixelBuffer dst, float strength, int size)
{
    dst.ParallelForEachPixel((x, y) =>
    {
        var (r, g, b, a) = src.GetPixel(x, y);

        float gxR = 0, gyR = 0;
        for (var dy = -1; dy <= 1; dy++)
        {
            for (var dx = -1; dx <= 1; dx++)
            {
                var (pr, _, _, _) = src.GetPixelWrapped(x + dx, y + dy);
                var sx = (dx == 0 ? 0f : dx > 0 ? 1f : -1f) * (dy == 0 ? 2f : 1f);
                var sy = (dy == 0 ? 0f : dy > 0 ? 1f : -1f) * (dx == 0 ? 2f : 1f);
                gxR += pr * sx;
                gyR += pr * sy;
            }
        }

        var emboss = (gxR + gyR) * strength * 0.5f + 0.5f;
        dst.SetPixel(x, y,
            Math.Clamp(emboss, 0f, 1f),
            Math.Clamp(emboss, 0f, 1f),
            Math.Clamp(emboss, 0f, 1f), a);
    });
}

private static void PixelOutline(PixelBuffer src, PixelBuffer dst, float strength, int size)
{
    dst.ParallelForEachPixel((x, y) =>
    {
        var (r, g, b, a) = src.GetPixel(x, y);

        // Compare with neighbors; if different enough, draw outline
        var (lr, lg, lb, _) = src.GetPixelWrapped(x - 1, y);
        var (ur, ug, ub, _) = src.GetPixelWrapped(x, y - 1);

        var diffH = MathF.Abs(r - lr) + MathF.Abs(g - lg) + MathF.Abs(b - lb);
        var diffV = MathF.Abs(r - ur) + MathF.Abs(g - ug) + MathF.Abs(b - ub);
        var diff = MathF.Max(diffH, diffV) * strength * 2f;

        if (diff > 0.3f)
        {
            // Outline pixel
            dst.SetPixel(x, y, 0f, 0f, 0f, a);
        }
        else
        {
            dst.SetPixel(x, y,
                Math.Clamp(r + diff * 0.5f, 0f, 1f),
                Math.Clamp(g + diff * 0.5f, 0f, 1f),
                Math.Clamp(b + diff * 0.5f, 0f, 1f), a);
        }
    });
}

private static void Posterize(PixelBuffer src, PixelBuffer dst, float strength, float detail, int size)
{
    var levels = Math.Max(2, (int)(2 + detail * 14));
    var step = 1f / levels;

    dst.ParallelForEachPixel((x, y) =>
    {
        var (r, g, b, a) = src.GetPixel(x, y);

        r = MathF.Round(r / step) * step;
        g = MathF.Round(g / step) * step;
        b = MathF.Round(b / step) * step;

        // Blend between original and posterized
        r = Lerp(r, src.GetPixel(x, y).R, 1f - strength);
        g = Lerp(g, src.GetPixel(x, y).G, 1f - strength);
        b = Lerp(b, src.GetPixel(x, y).B, 1f - strength);

        dst.SetPixel(x, y, r, g, b, a);
    });
}

private static void Watercolor(PixelBuffer src, PixelBuffer dst, float strength, float smoothness, int size)
{
    // Blur + color shift for watercolor effect
    var blurRadius = Math.Max(2, (int)(smoothness * 5) + 1);
    var temp = new PixelBuffer(size, size);

    // Box blur first pass
    temp.ParallelForEachPixel((x, y) =>
    {
        var sumR = 0f; var sumG = 0f; var sumB = 0f; var count = 0;
        for (var dx = -blurRadius; dx <= blurRadius; dx++)
        {
            var (pr, pg, pb, _) = src.GetPixelWrapped(x + dx, y);
            sumR += pr; sumG += pg; sumB += pb; count++;
        }
        var inv = 1f / count;
        temp.SetPixel(x, y, sumR * inv, sumG * inv, sumB * inv, 1f);
    });

    // Second pass with color bleeding
    dst.ParallelForEachPixel((x, y) =>
    {
        var sumR = 0f; var sumG = 0f; var sumB = 0f;
        var weights = 0f;
        for (var dy = -blurRadius; dy <= blurRadius; dy++)
        {
            for (var dx = -blurRadius; dx <= blurRadius; dx++)
            {
                var (pr, pg, pb, _) = temp.GetPixelWrapped(x + dx, y + dy);
                var dist = MathF.Sqrt(dx * dx + dy * dy);
                var w = MathF.Exp(-dist * dist / (2f * (blurRadius * 0.5f) * (blurRadius * 0.5f)));
                sumR += pr * w;
                sumG += pg * w;
                sumB += pb * w;
                weights += w;
            }
        }
        var invW = 1f / weights;

        // Add slight color variation (watercolor bleed)
        var bleed = strength * 0.1f;
        var (origR, origG, origB, a) = src.GetPixel(x, y);

        dst.SetPixel(x, y,
            Math.Clamp(Lerp(origR, sumR * invW, strength * 0.7f) + (sumR * invW - 0.5f) * bleed, 0f, 1f),
            Math.Clamp(Lerp(origG, sumG * invW, strength * 0.7f) + (sumG * invW - 0.5f) * bleed * 0.8f, 0f, 1f),
            Math.Clamp(Lerp(origB, sumB * invW, strength * 0.7f) + (sumB * invW - 0.5f) * bleed * 0.6f, 0f, 1f),
            a);
    });
    }
}
